// Return slots whose date is today or tomorrow (UTC)
const calendar = $input.first().json;
const slots = (calendar.content_slots || []);
const today = new Date();
const t = today.toISOString().slice(0, 10);
const tomorrow = new Date(today.getTime() + 86400000).toISOString().slice(0, 10);
const due = slots.filter(s => s.date === t || s.date === tomorrow);
if (due.length === 0) {
  return [];  // empty output halts downstream
}
return due.map(s => ({ json: s }));

const resp = $input.item.json;
const text = (resp.content || []).map(b => b.text || '').join('\n').trim();
if (!text) throw new Error('Claude returned empty content');
const cleanText = text.replace(/\*\*([^*]+)\*\*/g, '$1').replace(/\*([^*]+)\*/g, '$1').replace(/^#+\s+/gm, '').replace(/^[-*]\s+/gm, '').replace(/`([^`]+)`/g, '$1');
const ctx = $('Build Prompt').item.json;

// Strip or limit hashtags based on platform
let finalText = cleanText;
const platform = ctx.platform || '';
if (platform === 'linkedin' || platform === 'facebook') {
  // Remove all hashtags from LinkedIn and Facebook
  finalText = cleanText.replace(/\n*#\S+/g, '').trim();
} else if (platform === 'instagram') {
  // Keep max 5 hashtags on Instagram
  const hashtagRegex = /#\S+/g;
  const allTags = cleanText.match(hashtagRegex) || [];
  if (allTags.length > 5) {
    // Remove all hashtags first, then append only first 5
    const bodyWithoutTags = cleanText.replace(/\n*#\S+/g, '').trim();
    finalText = bodyWithoutTags + '\n\n' + allTags.slice(0, 5).join(' ');
  }
}

const firstLine = cleanText.split('\n').map(s => s.trim()).find(Boolean) || '';
const title = firstLine.length > 80 ? firstLine.slice(0, 77) + '...'
                                     : (firstLine || ((ctx.theme || 'Crete') + ' - ' + ctx.platform));
return {
  status: 'pending_review',
  content_type: ctx.content_type,
  platform: ctx.platform,
  title,
  body: finalText,
  cta: ctx.cta,
  theme: ctx.theme,
  scheduled_for: ctx.scheduled_for,
  generation_prompt: ctx.user_prompt,
  metadata: { slot_id: ctx.slot_id, generated_by: 'crete-content-generator' },
  image_type: ctx.image_type || null,
  image_style: ctx.image_style || null,
  image_theme: ctx.image_theme || null,
  media_url: null
};

