// Route row to image generation based on platform + image_type.
// Pre-Slice-4: early-returned for any non-Instagram row (FB/LinkedIn rows got media_url=null).
// Slice 4: open to Instagram + Facebook + LinkedIn. Rows on other platforms still pass through
// untouched (no _needsImage / _needsPhoto flags → straight to Insert with media_url=null per Build Row).
const row = $input.item.json;
const platform = (row.platform || '').toLowerCase();
const NEEDS_IMAGE = ['instagram', 'facebook', 'linkedin'];

if (!NEEDS_IMAGE.includes(platform)) {
  return row;
}

const imageType = row.image_type || 'text_card';

if (imageType === 'photo') {
  return { ...row, _needsPhoto: true, _photoTheme: row.image_theme || '' };
}

const style = row.image_style || 'quote';
const body = row.body || '';
const sentences = body.match(/[^.!?]+[.!?]+/g) || [body.slice(0, 200)];

let apiBody;
if (style === 'editorial') {
  apiBody = {
    style: 'editorial',
    headline: (sentences[0] || '').trim().slice(0, 200),
    body: (sentences[1] || '').trim().slice(0, 300)
  };
} else {
  const quoteText = sentences.slice(0, 2).join(' ').trim().slice(0, 400);
  apiBody = { style: 'quote', text: quoteText };
}

return { ...row, _needsImage: true, _apiBody: apiBody };

// Merge generator response into row. Throws loudly if generator failed.
const apiResp = $input.item.json;
const row = $('Image Router').item.json;
if (apiResp && apiResp.url) {
  const { _needsImage, _apiBody, ...cleanRow } = row;
  cleanRow.media_url = apiResp.url;
  cleanRow.metadata = { ...(row.metadata || {}), image_source: 'generator' };
  return cleanRow;
}
throw new Error(
  'generate-image API returned no url for slot ' +
  (row.metadata?.slot_id || row.title || 'unknown') +
  '. Response: ' + JSON.stringify(apiResp || {}).slice(0, 500)
);

// Select a random photo from library, filtered by theme. Throws if none usable.
// $input.item.json IS the photo-library response (contains photos[]); the actual row
// context (title/body/platform/etc.) lives upstream. Two upstream paths feed here:
//   - normal photo path: Image Router emitted {_needsPhoto:true,...}
//   - text-card-failed fallback path: Photo Fallback emitted {_fallback_from_generator:true,...}
// Use Photo Fallback's output if it ran, else Image Router. $() throws if a node
// didn't run in this execution, so guard with try/catch.
let row;
try {
  const fb = $('Photo Fallback').item.json;
  row = (fb && fb._fallback_from_generator) ? fb : $('Image Router').item.json;
} catch (e) {
  row = $('Image Router').item.json;
}
const photoLib = $('Fetch Photo Library').item.json;
const photos = photoLib?.photos || photoLib?.body?.photos || [];
if (!Array.isArray(photos) || photos.length === 0) {
  throw new Error('Photo library returned 0 photos. Theme=' + (row._photoTheme || row.image_theme || 'any'));
}
const theme = (row._photoTheme || row.image_theme || row.theme || '').toLowerCase();
let pool = photos;
if (theme) {
  const themed = photos.filter(p => ((p.theme || '') + ' ' + ((p.tags || []).join(' '))).toLowerCase().includes(theme));
  if (themed.length > 0) pool = themed;
}
const selected = pool[Math.floor(Math.random() * pool.length)];
if (!selected || !selected.public_url) {
  throw new Error('Photo library returned no usable photo for theme: ' + (theme || 'any') + '. Library size: ' + photos.length);
}
// Strip ALL transient flags including _needsImage/_apiBody (set by Image Router on text-card path,
// would leak through on the fallback path).
const { _needsPhoto, _photoTheme, _fallback_from_generator, _needsImage, _apiBody, ...cleanRow } = row;
cleanRow.media_url = selected.public_url;
cleanRow.metadata = { ...(row.metadata || {}), image_source: row._fallback_from_generator ? 'library_fallback' : 'library', photo_id: selected.id };
return cleanRow;

// Fallback when generate-image errors: queue photo path, mark fallback for downstream alert.
const row = $('Image Router').item.json;
return {
  ...row,
  _needsPhoto: true,
  _photoTheme: row.image_theme || row.theme || '',
  _fallback_from_generator: true
};

